// src/components/Section/Section.jsx
import React, { useEffect, useState } from "react";
import axios from "axios";
import Card from "../Card/Card";
import Carousel from "../Carousel/Carousel"; // you'll create this
import styles from "./Section.module.css";

const TOP_ALBUMS_URL = "https://qtify-backend.labs.crio.do/albums/top";

function Section() {
  const [albums, setAlbums] = useState([]);
  const [isCollapsed, setIsCollapsed] = useState(false); // false = grid, true = carousel

  useEffect(() => {
    axios
      .get(TOP_ALBUMS_URL)
      .then((res) => setAlbums(res.data))
      .catch((err) => {
        console.error("Failed to fetch top albums", err);
      });
  }, []);

  const handleToggle = () => {
    setIsCollapsed((prev) => !prev);
  };

  return (
    <section className={styles.section}>
      <div className={styles.header}>
        <h2 className={styles.title}>Top Albums</h2>
        <button className={styles.collapse} onClick={handleToggle}>
          {isCollapsed ? "Show All" : "Collapse"}
        </button>
      </div>

      {isCollapsed ? (
        <Carousel items={albums}>
          {albums.map((album) => (
            <Card
              key={album.id}
              image={album.image}
              title={album.title}
              subtitle={`${album.follows} Follows`}
            />
          ))}
        </Carousel>
      ) : (
        <div className={styles.grid}>
          {albums.map((album) => (
            <Card
              key={album.id}
              image={album.image}
              title={album.title}
              subtitle={`${album.follows} Follows`}
            />
          ))}
        </div>
      )}
    </section>
  );
}

export default Section;
